create table dirkspzm32.isi_avis_pos (
    lieferanten_nr           varchar2(9 char) not null enable,
    slb_nr                   varchar2(8 char) not null enable,
    lieferschein_nr          varchar2(8 char) not null enable,
    lieferschein_pos         number(*, 5) not null enable,
    sach_nr_kunde            varchar2(22 char) not null enable,
    sach_nr_lieferant        varchar2(22 char) not null enable,
    ursprungsland            varchar2(3 char) not null enable,
    liefermenge_kunde        number(*, 3) not null enable,
    me_kunde                 varchar2(2 char) not null enable,
    liefermenge_lieferant    number(*, 3),
    me_lieferant             varchar2(2 char),
    umsatzsteuersatz         number(*, 6),
    abruf_schluessel         varchar2(1 char),
    chargen_nr               varchar2(15 char),
    verwendung_schluessel    varchar2(1 char) not null enable,
    gefahr_stoff_schluessel  varchar2(8 char),
    praeferenz_status        varchar2(1 char),
    zollgut                  varchar2(1 char) default ' ' not null enable,
    geaendert_schluessel     varchar2(2 char) default '  ' not null enable,
    ursprung_lieferschein_nr varchar2(8 char),
    text_1                   varchar2(40 char),
    text_2                   varchar2(40 char),
    text_3                   varchar2(40 char),
    bearbeitungs_status      varchar2(1 char) default 'N' not null enable,
    storno_grund             varchar2(100 char)
);

alter table dirkspzm32.isi_avis_pos
    add constraint pk_isi_avis_pos
        primary key ( lieferanten_nr,
                      slb_nr,
                      lieferschein_nr,
                      lieferschein_pos )
            using index enable;


